Graph coding: Minimum Bottleneck Latency:
import heapq

def min_bottleneck_path(n, edges, start, end):
    if start == end:
        return 0
    graph = {i: [] for i in range(n)}
    for u, v, w in edges:
        graph[u].append((v, w))

    dist = [float("inf")] * n
    dist[start] = 0
    pq = [(0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        if u == end:
            return d
        for v, w in graph[u]:
            nd = max(d, w)
            if nd < dist[v]:
                dist[v] = nd
                heapq.heappush(pq, (nd, v))
    return -1 if dist[end] == float("inf") else dist[end]
This is a modified Dijkstra (minimax path): instead of summing edge weights, relax with max(current_bottleneck, edge_weight) and always pop the smallest bottleneck first from the heap. Runs in O((V + E) log V).

