from collections import deque

def levelOrder(root):
    if not root:
        return []
    result = []
    queue = deque([root])
    while queue:
        level = []
        for _ in range(len(queue)):
            node = queue.popleft()
            level.append(node.val)
            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)
        result.append(level)
    return result
Standard BFS with a queue: snapshot the queue's current length before the inner loop so each iteration processes exactly one level's worth of nodes before moving to the next. O(n) time, O(n) space.

