import time
import functools

def timed(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.perf_counter()
        try:
            return func(*args, **kwargs)
        finally:
            elapsed = time.perf_counter() - start
            print(f"{func.__name__} took {elapsed:.4f}s")
    return wrapper
functools.wraps copies __name__, __doc__, and other metadata from the wrapped function onto the wrapper, so introspection, help(), and stack traces still show the original function's identity instead of "wrapper".

